<template>
  <main class="p2-redesign">
    <section v-if="page === 'login'" class="login-screen">
      <div class="login-panel">
        <div class="login-card">
          <div class="brand brand-center"><span class="brand-mark">P</span><span><b>Pauliceia</b><small>2.0</small></span></div>
          <h1>Boas-vindas ao Pauliceia!</h1>
          <p class="muted">Entre com sua conta para continuar</p>
          <form class="form" @submit.prevent="submitLogin">
            <label class="field"><span>E-mail</span><input v-model="login.email" :class="{ danger: loginError }" type="email" placeholder="seu@email.com" /></label>
            <label class="field"><span>Senha</span><div class="password"><input v-model="login.password" :class="{ danger: loginError }" :type="showPassword ? 'text' : 'password'" placeholder="Digite sua senha" /><button type="button" @click="showPassword=!showPassword" :aria-label="showPassword ? 'Ocultar senha' : 'Mostrar senha'">{{ showPassword ? '◌' : '◉' }}</button></div></label>
            <p v-if="loginError" class="error">Informe seu e-mail e senha para continuar.</p>
            <div class="row between"><label class="check"><input v-model="remember" type="checkbox" /><span></span>Lembrar de mim</label><button type="button" class="link" @click="openModal('recover')">Esqueceu a senha?</button></div>
            <button class="btn primary block" type="submit">↪ Entrar</button>
          </form>
          <div class="divider"><span>ou continue com</span></div>
          <div class="social"><button class="btn outline" @click="toastIt('Login social indisponível no protótipo')">Google</button><button class="btn outline" @click="toastIt('Login social indisponível no protótipo')">GitHub</button></div>
          <p class="center muted">Não tem uma conta? <button class="link" @click="openModal('register')">Criar conta</button></p>
        </div>
      </div>
      <aside class="login-image"><div class="hero-copy"><p>⌖ São Paulo Histórica</p><h2>Explore a história de São Paulo através dos mapas</h2><p>Descubra como a cidade evoluiu entre 1870 e 1940 com mapas históricos georreferenciados.</p></div></aside>
    </section>

    <section v-else-if="page === 'home'" class="home-screen">
      <prototype-header active="home" :language="language" @nav="go" @modal="openModal" @popover="openPopover" @language="toggleLanguage" />
      <section class="hero-home">
        <div class="hero-content"><span class="pill">Plataforma de mapeamento histórico</span><h1>Explore a história de <em>São Paulo</em> através dos mapas</h1><p>Uma plataforma colaborativa para pesquisadores, estudantes e curiosos explorarem a transformação urbana de São Paulo entre 1870 e 1940.</p><div class="actions"><button class="btn primary" @click="go('map')">▧ Explorar o mapa</button><button class="btn light" @click="scrollTools">⌕ Saiba mais sobre o projeto</button></div></div>
      </section>
      <section class="metrics"><article v-for="metric in metrics" :key="metric.label"><b>{{ metric.value }}</b><span>{{ metric.label }}</span></article></section>
      <section id="tools" class="tools"><div class="section-title"><h2>Ferramentas para sua <em>pesquisa</em></h2><p>Ferramentas poderosas para pesquisa histórica e análise geoespacial.</p></div><div class="tool-grid"><article v-for="tool in tools" :key="tool.title" class="tool-card" tabindex="0"><span>{{ tool.icon }}</span><h3>{{ tool.title }}</h3><p>{{ tool.description }}</p></article></div></section>
      <footer class="footer"><div><div class="brand dark"><span class="brand-mark">P</span><span><b>Pauliceia</b><small>2.0</small></span></div><p>Plataforma colaborativa de mapeamento histórico de São Paulo.</p></div><nav><b>Links rápidos</b><button @click="go('map')">Explorar Mapa</button><button @click="toastIt('Página em construção')">Sobre o Projeto</button><button @click="toastIt('Página em construção')">Contato</button><button @click="go('login')">Entrar</button></nav><nav><b>Recursos</b><button @click="toastIt('Página em construção')">Documentação</button><button @click="toastIt('Página em construção')">API</button><button @click="toastIt('Página em construção')">Tutorial</button></nav></footer>
    </section>

    <section v-else class="map-screen">
      <prototype-header active="map" :language="language" @nav="go" @modal="openModal" @popover="openPopover" @language="toggleLanguage" />
      <div class="map-layout" :class="{ collapsed: sidebarCollapsed }">
        <aside class="sidebar">
          <div class="tabs"><button :class="{ active: mapTab==='maps' }" @click="mapTab='maps'">▧ Mapas</button><button :class="{ active: mapTab==='layers' }" @click="mapTab='layers'">▱ Camadas</button></div>
          <template v-if="mapTab==='layers'">
            <div class="side-head"><h2>Camadas de dados <small>({{ filteredLayers.length }})</small></h2><button class="ghost" @click="openModal('filters')">⌕ Filtrar</button></div>
            <label class="search"><span>⌕</span><input v-model="layerSearch" placeholder="Pesquisar camadas" /></label>
            <div v-if="filteredLayers.length" class="scroll-list"><article v-for="layer in filteredLayers" :key="layer.id" class="layer-card" :class="{ selected: layer.active }"><div class="card-main"><span class="dot" :style="{ background: layer.color }"></span><div><h3>{{ layer.title }}</h3><p>{{ layer.author }}</p></div><label class="switch"><input type="checkbox" v-model="layer.active" :aria-label="'Ativar camada '+layer.title" /><span></span></label></div><div class="badges"><span v-for="tag in layer.tags" :key="tag">{{ tag }}</span></div><div class="card-actions"><button class="ghost" :class="{ orange: layer.favorite }" @click="toggleFavorite(layer)">{{ layer.favorite ? '★ Favoritado' : '♡ Favoritar' }}</button><button class="ghost" @click="showLayer(layer)">ⓘ Detalhes</button></div></article></div>
            <div v-else class="empty"><b>Nenhuma camada encontrada</b><button class="btn outline" @click="layerSearch=''">Limpar busca</button></div>
          </template>
          <template v-else>
            <div class="side-head"><h2>Mapas Base</h2></div><label class="search"><span>⌕</span><input v-model="mapSearch" placeholder="Pesquisar mapas" /></label><div class="scroll-list"><article v-for="base in filteredBaseMaps" :key="base.id" class="base-card" :class="{ selected: base.active }"><div><h3>{{ base.title }}</h3><p>{{ base.description }}</p></div><label class="switch"><input type="checkbox" :checked="base.active" @change="selectBase(base.id)" :aria-label="'Ativar mapa base '+base.title" /><span></span></label></article></div>
          </template>
        </aside>
        <button class="collapse" @click="sidebarCollapsed=!sidebarCollapsed" :aria-label="sidebarCollapsed ? 'Expandir sidebar' : 'Recolher sidebar'">{{ sidebarCollapsed ? '›' : '‹' }}</button>
        <section class="map-canvas" :class="activeBaseClass">
          <div class="fake-map"></div>
          <div class="map-search"><label class="search address"><span>⌕</span><input v-model="addressSearch" placeholder="Buscar endereço: rua, número, ano" @keyup.enter="performSearch" /></label><button class="btn icon primary" @click="performSearch" aria-label="Buscar">⌕</button><button class="btn icon" @click="openModal('upload')" aria-label="Upload">⇧</button></div><p v-if="searchError" class="map-error">Digite um endereço para buscar.</p>
          <span v-for="point in visiblePoints" :key="point.id" class="map-point" :style="{ left: point.x+'%', top: point.y+'%', background: point.color }"></span><span v-if="searchMarker" class="marker" :style="{ left: searchMarker.x+'%', top: searchMarker.y+'%' }">Endereço encontrado</span>
          <div class="legend"><h3>Legenda</h3><p><span class="orange-dot"></span>Encontrado</p><p><span class="blue-dot"></span>Geocodificado</p><p><span class="yellow-dot"></span>Extrapolado</p></div>
          <div class="zoom"><button class="btn icon" @click="zoomLevel++" aria-label="Aproximar mapa">＋</button><button class="btn icon" @click="zoomLevel--" aria-label="Afastar mapa">−</button><button class="btn icon" @click="toastIt('Mapa centralizado')" aria-label="Centralizar mapa">⌖</button></div><span class="zoom-level">Zoom {{ zoomLevel }}</span>
          <div class="timeline"><span>◷</span><input v-model.number="startYear" type="number" min="1868" max="1940" /><input v-model.number="startYear" type="range" min="1868" max="1940" /><input v-model.number="endYear" type="range" min="1868" max="1940" /><input v-model.number="endYear" type="number" min="1868" max="1940" /><b>{{ orderedYears.start }}–{{ orderedYears.end }}</b></div>
        </section>
      </div>
    </section>

    <section v-if="modal" class="overlay" role="dialog" aria-modal="true"><div class="modal"><button class="modal-close" @click="closeModal" aria-label="Fechar">×</button>
      <template v-if="modal==='register'"><h2>Criar conta</h2><p>Cadastro simulado para o protótipo navegável.</p><label class="field"><span>Nome</span><input placeholder="Seu nome" /></label><label class="field"><span>E-mail</span><input placeholder="seu@email.com" /></label><div class="modal-actions"><button class="btn outline" @click="closeModal">Cancelar</button><button class="btn primary" @click="toastIt('Conta criada no protótipo'); closeModal()">Cadastrar</button></div></template>
      <template v-else-if="modal==='recover'"><h2>Recuperar senha</h2><p>Informe seu e-mail para receber instruções.</p><label class="field"><span>E-mail</span><input placeholder="seu@email.com" /></label><div class="modal-actions"><button class="btn outline" @click="closeModal">Cancelar</button><button class="btn primary" @click="toastIt('Instruções enviadas'); closeModal()">Enviar</button></div></template>
      <template v-else-if="modal==='filters'"><h2>Filtrar camadas</h2><div class="filter-grid"><label class="field"><span>Período</span><input :value="orderedYears.start + '–' + orderedYears.end" /></label><label class="field"><span>Autor</span><input placeholder="Nome do autor" /></label><label class="field"><span>Categoria</span><input placeholder="Ex.: enchente" /></label><label class="field"><span>Status</span><input placeholder="Ativa ou inativa" /></label></div><div class="modal-actions"><button class="btn outline" @click="layerSearch=''; closeModal()">Limpar filtros</button><button class="btn primary" @click="toastIt('Filtros aplicados'); closeModal()">Aplicar filtros</button></div></template>
      <template v-else-if="modal==='upload'"><h2>Enviar lista de endereços</h2><p>Formatos aceitos: CSV.</p><div class="dropzone"><span>⇧</span><b>Arraste seu arquivo aqui</b><small>ou clique em selecionar arquivo</small></div><div class="modal-actions"><button class="btn outline" @click="closeModal">Cancelar</button><button class="btn primary" @click="simulateUpload">{{ uploading ? 'Enviando...' : 'Enviar' }}</button></div></template>
      <template v-else-if="modal==='layer' && selectedLayer"><h2>{{ selectedLayer.title }}</h2><p><b>Autor:</b> {{ selectedLayer.author }}</p><p>Camada histórica georreferenciada para análise espacial da Pauliceia 2.0.</p><div class="badges"><span v-for="tag in selectedLayer.tags" :key="tag">{{ tag }}</span></div><p><b>Período:</b> {{ orderedYears.start }}–{{ orderedYears.end }}</p><div class="modal-actions"><button class="btn outline" @click="toggleFavorite(selectedLayer)">Favoritar</button><button class="btn primary" @click="selectedLayer.active=!selectedLayer.active; closeModal()">{{ selectedLayer.active ? 'Desativar camada' : 'Ativar camada' }}</button></div></template>
      <template v-else><h2>Ajuda do mapa</h2><p>Use a sidebar para alternar mapas base e camadas. A busca localiza endereços e a linha do tempo filtra o intervalo histórico.</p></template>
    </div></section>
    <aside v-if="popover" class="popover"><b>{{ popover.title }}</b><button v-for="item in popover.items" :key="item" @click="handlePopover(item)">{{ item }}</button></aside><div v-if="toast" class="toast">{{ toast }}</div>
  </main>
</template>

<script>
const PrototypeHeader = { name: 'prototype-header', props: ['active', 'language'], methods: { menu: function(kind) { const menus = { share: { title: 'Compartilhar', items: ['Copiar link do mapa'] }, download: { title: 'Download', items: ['Baixar PNG', 'Baixar CSV', 'Baixar GeoJSON'] }, user: { title: 'Usuário', items: ['Minha conta', 'Sair'] } }; this.$emit('popover', menus[kind]); } }, template: '<header class="topbar"><button class="brand" @click="$emit(\'nav\',\'home\')"><span class="brand-mark">P</span><span><b>Pauliceia</b><small>2.0</small></span></button><nav><button :class="{active:active===\'home\'}" @click="$emit(\'nav\',\'home\')">Início</button><button :class="{active:active===\'map\'}" @click="$emit(\'nav\',\'map\')">Mapa</button><button @click="$emit(\'modal\',\'help\')">Sobre</button><button @click="$emit(\'modal\',\'help\')">Tutorial</button><button @click="$emit(\'modal\',\'help\')">Contato</button></nav><div class="top-actions"><button class="lang" @click="$emit(\'language\')">{{ language }}</button><button class="round" @click="menu(\'share\')" aria-label="Compartilhar">↗</button><button class="round" @click="menu(\'download\')" aria-label="Download">↓</button><button class="round" @click="$emit(\'modal\',\'help\')" aria-label="Ajuda">?</button><button class="round" @click="menu(\'user\')" aria-label="Usuário">◌</button><button class="btn outline" @click="$emit(\'modal\',\'register\')">Cadastrar-se</button><button class="btn primary" @click="$emit(\'nav\',\'login\')">Entrar</button></div></header>' };
export default { name: 'RedesignPrototype', components: { PrototypeHeader }, data: function() { return { language: 'PT', login: { email: '', password: '' }, loginError: false, showPassword: false, remember: false, modal: null, popover: null, toast: '', uploading: false, mapTab: 'layers', sidebarCollapsed: false, layerSearch: '', mapSearch: '', addressSearch: '', searchError: false, searchMarker: null, selectedLayer: null, zoomLevel: 14, startYear: 1868, endYear: 1940, metrics: [{ value: '50+', label: 'Mapas históricos' }, { value: '200+', label: 'Camadas de dados' }, { value: '1.200+', label: 'Pesquisadores' }, { value: '70', label: 'Anos cobertos' }], tools: [{ icon: '▧', title: 'Mapas históricos', description: 'Explore mapas detalhados de São Paulo entre 1870 e 1940.' }, { icon: '◷', title: 'Navegação temporal', description: 'Use o slider temporal para viajar no tempo.' }, { icon: '⌕', title: 'Busca de endereços', description: 'Pesquise endereços históricos por rua, número e ano.' }, { icon: '▱', title: 'Camadas colaborativas', description: 'Crie e compartilhe camadas de dados geográficos.' }, { icon: '⇧', title: 'Upload de dados', description: 'Importe pesquisas em CSV e visualize no mapa.' }, { icon: '↓', title: 'Exportação', description: 'Baixe dados e imagens para documentação.' }], layers: [{ id: 'flood-1850', title: 'A enchente de 1850', author: 'Orlando Guarnieri', tags: ['enchente', 'anhangabaú'], color: '#2563EB', active: false, favorite: false, points: [{ x: 66, y: 42 }, { x: 72, y: 48 }] }, { id: 'flood-1929', title: 'A enchente de 1929 em SP', author: 'Luis A. C. Ferla', tags: ['enchente', 'história ambiental'], color: '#16A34A', active: true, favorite: false, points: [{ x: 59, y: 54 }, { x: 73, y: 59 }, { x: 82, y: 46 }] }, { id: 'sewer-1893', title: 'Área servida de esgotos até 1893', author: 'Orlando Guarnieri', tags: ['esgoto', 'cantareira'], color: '#DC2626', active: true, favorite: false, points: [{ x: 62, y: 36 }, { x: 78, y: 34 }] }, { id: 'queer-1939', title: 'Áreas ocupadas por homossexuais 1939 a 1959', author: 'Cintia Almeida', tags: ['resistência', 'homossexuais'], color: '#9333EA', active: false, favorite: false, points: [{ x: 69, y: 63 }] }, { id: 'schools-1892', title: 'Anuário de escolas até 1892', author: 'Cintia Almeida', tags: ['educação', 'institucional'], color: '#0891B2', active: false, favorite: false, points: [{ x: 57, y: 46 }, { x: 84, y: 62 }] }], baseMaps: [{ id: 'osm', title: 'OpenStreetMap', description: 'Mapa base atual', active: true }, { id: 'sp1930', title: 'São Paulo 1930', description: 'Levantamento SARA Brasil 1:5000', active: false }, { id: 'sp1924', title: 'São Paulo 1924', description: 'Mapa da cidade - 1924', active: false }, { id: 'sp1905', title: 'São Paulo 1905', description: 'Planta geral da capital', active: false }, { id: 'sp1890', title: 'São Paulo 1890', description: 'Planta da cidade', active: false }, { id: 'sp1881', title: 'São Paulo 1881', description: 'Mapa cadastral', active: false }, { id: 'sp1877', title: 'São Paulo 1877', description: 'Carta da capital', active: false }, { id: 'sp1868', title: 'São Paulo 1868', description: 'Planta da imperial cidade', active: false }] }; }, computed: { page: function() { if (this.$route.name === 'Login' || this.$route.path.indexOf('/login') === 0) return 'login'; if (this.$route.name === 'Explore' || this.$route.path.indexOf('/explore') === 0) return 'map'; return 'home'; }, filteredLayers: function() { const q = this.layerSearch.toLowerCase().trim(); return q ? this.layers.filter(function(l) { return [l.title, l.author].concat(l.tags).join(' ').toLowerCase().indexOf(q) !== -1; }) : this.layers; }, filteredBaseMaps: function() { const q = this.mapSearch.toLowerCase().trim(); return q ? this.baseMaps.filter(function(m) { return (m.title + ' ' + m.description).toLowerCase().indexOf(q) !== -1; }) : this.baseMaps; }, visiblePoints: function() { const items = []; this.layers.filter(function(l) { return l.active; }).forEach(function(l) { l.points.forEach(function(p, i) { items.push({ id: l.id + '-' + i, color: l.color, x: p.x, y: p.y }); }); }); return items; }, orderedYears: function() { return { start: Math.min(this.startYear, this.endYear), end: Math.max(this.startYear, this.endYear) }; }, activeBaseClass: function() { const active = this.baseMaps.find(function(m) { return m.active; }); return active ? 'base-' + active.id : 'base-osm'; } }, methods: { go: function(target) { const path = target === 'login' ? '/login' : target === 'map' ? '/explore' : '/home'; if (this.$route.path !== path) this.$router.push(path); }, submitLogin: function() { if (!this.login.email || !this.login.password) { this.loginError = true; return; } this.go('home'); }, scrollTools: function() { const el = document.getElementById('tools'); if (el) el.scrollIntoView({ behavior: 'smooth' }); }, openModal: function(name) { this.modal = name; this.popover = null; }, closeModal: function() { this.modal = null; this.selectedLayer = null; }, openPopover: function(data) { this.popover = data; }, handlePopover: function(item) { if (item === 'Sair') this.go('login'); else this.toastIt(item === 'Copiar link do mapa' ? 'Link copiado' : item); this.popover = null; }, toastIt: function(message) { this.toast = message; const self = this; setTimeout(function() { self.toast = ''; }, 2200); }, toggleLanguage: function() { this.language = this.language === 'PT' ? 'EN' : 'PT'; this.toastIt('Idioma ' + this.language); }, toggleFavorite: function(layer) { layer.favorite = !layer.favorite; this.toastIt(layer.favorite ? 'Camada favoritada' : 'Camada removida dos favoritos'); }, showLayer: function(layer) { this.selectedLayer = layer; this.openModal('layer'); }, selectBase: function(id) { this.baseMaps.forEach(function(m) { m.active = m.id === id; }); }, performSearch: function() { if (!this.addressSearch.trim()) { this.searchError = true; return; } this.searchError = false; this.searchMarker = { x: 72, y: 42 }; this.toastIt('Endereço encontrado'); }, simulateUpload: function() { const self = this; this.uploading = true; setTimeout(function() { self.uploading = false; self.closeModal(); self.searchMarker = { x: 67, y: 50 }; self.toastIt('Arquivo enviado com sucesso'); }, 900); } } };
</script>

<style scoped>
